import test from 'node:test';
import assert from 'node:assert/strict';
import { PolicyStore } from '../src/policy-store.mjs';
import { AuditLog } from '../src/audit-log.mjs';
import { Authorizer } from '../src/authorizer.mjs';

test('a request keeps the policy that allowed it when a role is revoked mid-flight', async () => {
  let releaseIdentity;
  const identityReady = new Promise((resolve) => {
    releaseIdentity = resolve;
  });
  const store = new PolicyStore({ '/exports': ['analyst'] });
  const audit = new AuditLog(store);
  const authorizer = new Authorizer({
    store,
    audit,
    resolveIdentity: () => identityReady,
  });

  const pending = authorizer.authorize({ token: 'slow', route: '/exports' });
  await Promise.resolve();
  store.replace({ '/exports': ['admin'] });
  releaseIdentity({ subject: 'user-9', role: 'analyst' });

  assert.deepEqual(await pending, {
    subject: 'user-9',
    route: '/exports',
    allowed: true,
    policyVersion: 1,
  });
  assert.deepEqual(audit.entries(), [{
    subject: 'user-9',
    route: '/exports',
    allowed: true,
    policyVersion: 1,
  }]);
});
